var e=JSON.parse(`[{"id":"L2_1","type":"narration","speaker":null,"text":{"KOREA":"신은 인간을 사랑했다.","JPN":"神は人間を愛した。","ENG":"God loved humans.","TWN":"神曾經愛過人類。"},"stage":{"bg":"BLACK","bgm":"THEMA_NANAHARA_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"narration","speaker":null,"text":{"KOREA":"그렇게 신과 인간 사이에 자손이 태어났다.","JPN":"そうして神と人間の間に子が生まれた。","ENG":"And thus, a newborn child emerged between God and a human.","TWN":"就這樣，神與人之間生出後裔。"},"stage":{"bg":"BLACK","bgm":"THEMA_NANAHARA_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"narration","speaker":null,"text":{"KOREA":"신은 그의 자손에게 많은 걸 베풀고 싶었다.","JPN":"神は自らの子孫に与えられる限りの恩恵を与えたかった。","ENG":"God wanted to give her child everything.","TWN":"神想把一切都給他的後裔。"},"stage":{"bg":"BLACK","bgm":"THEMA_NANAHARA_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"narration","speaker":null,"text":{"KOREA":"그래서 인간들이 자신을 섬기는 것처럼……","JPN":"それで人間が神に仕えるのと同じように……","ENG":"Just as humans worshiped her...","TWN":"於是像人類侍奉自己一樣……"},"stage":{"bg":"BLACK","bgm":"THEMA_NANAHARA_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"narration","speaker":null,"text":{"KOREA":"아이에게 권능을 주고, 무녀로 섬겼다.","JPN":"子に権能を与え、巫女として仕えさせた。","ENG":"She empowered her child, and appointed her child as a priestess.","TWN":"給予後裔權能做巫女侍奉神。"},"stage":{"bg":"BLACK","bgm":"THEMA_NANAHARA_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"GOD_NPC_NANAHARA2_NULL","text":{"KOREA":"이걸로, 여덟 머리 중 일곱을 베었도다.","JPN":"これで、八つの頭のうち七つを切り取った。","ENG":"Seven severed. Only one left, thou.","TWN":"已經斬掉八顆中的七顆，"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"GOD_NPC_NANAHARA2_NULL","text":{"KOREA":"하지만 너의 독기는 여전히 이승을 허물고 있으니…… 이대로는 세상이 무너지고 말리라.","JPN":"だが、お主の毒気はいまだ現世を侵し続けている……このままでは世界は崩壊してしまうであろう。","ENG":"Yet, thy venom still lingers in this world... collapsed shall it be if left unchecked.","TWN":"但你的毒氣依舊在摧毀現世……再這樣下去，世界會毀滅的。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"GOD_NPC_NANAHARA2_NULL","text":{"KOREA":"그러니, 네 마지막 머리를 베어야겠구나. 역신 오로치여.","JPN":"それゆえ、お主の最後の頭を切り取らねばならぬ。疫病神オロチよ。","ENG":"Thus, I shall sever thy last head as well, Orochi the Plague God.","TWN":"因此，必須斬掉你最後一顆頭，瘟神大蛇。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"이 몸은 죽지 않는다. 망자를 다스리는 네놈이라면 잘 알고 있을 텐데?","JPN":"我は死なん。亡者を治める貴様ならよく知っているはずだ。","ENG":"I am immortal. You, the ruler of death, should know this, no?","TWN":"這副軀體是不會死的，管理死人的你應該很清楚吧？"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"GOD_NPC_NANAHARA2_NULL","text":{"KOREA":"네 머리들을 베어 봉한다면, 다시 쉽게 인간들을 해칠 순 없겠지.","JPN":"頭を切り封印すれば、人間を容易く害することはできなくなる。","ENG":"With thy heads sealed, thou shalt not easily cast doom on man.","TWN":"等我把你的頭斬下，再將你封印起來，你便無法再危害人類。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"나는……!","JPN":"我は……！","ENG":"I...!","TWN":"我……！"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"……인간을 믿었다.","JPN":"……人間を信じた。","ENG":"...Trusted them.","TWN":"……曾經那麼相信人類，"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"하지만 그것들은……","JPN":"しかし、あやつらは……","ENG":"But those vile creatures...","TWN":"他們卻……"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"내가…… 가장 소중히 여기는 분을 죽였어.","JPN":"我が……もっとも大切にしていた人間を殺した。","ENG":"They... They slaughtered my beloved.","TWN":"殺死……我的摯愛。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"그 힘을 빼앗아, 영생을 얻겠다는 이유만으로!","JPN":"その力を奪い、永生を得たいという理由だけで！","ENG":"All because they wanted to take her powers and gain eternal life!","TWN":"只因為他們相信，奪取她的力量可以得到永生！"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"GOD_NPC_NANAHARA2_NULL","text":{"KOREA":"알고 있다네.","JPN":"わかっている。","ENG":"So I am aware.","TWN":"我知道。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"GOD_NPC_NANAHARA2_NULL","text":{"KOREA":"우리 같은 존재는 인간처럼 한 번 품은 감정을 망각하지 못하지.","JPN":"我らのような存在は人間のように一度胸に抱いた感情を忘却できぬ。","ENG":"Being who we are, we do not forget feelings once embraced, unlike humans.","TWN":"像我們這類的存在，一旦投入感情便無法遺忘。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"GOD_NPC_NANAHARA2_NULL","text":{"KOREA":"그렇기에, 한 차례 인간을 증오해버리면 역신이 되고 마는 것이야.","JPN":"だからこそ、一度人間を憎み始めると疫病神になってしまうのだ。","ENG":"Thus, hatred towards humans turns us into Plague Gods.","TWN":"因此只要憎恨人類一次，就會成為瘟神。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"욕망에 더럽혀지기 전에, 내가 그 영혼들을 거두어 가려는 것 뿐이다.","JPN":"欲望にまみれてしまう前に、我がその魂を摘みとろうというだけだ。","ENG":"I am merely reaping their souls before they are further tainted by temptation.","TWN":"我只是在他們墮落前收走他們的靈魂而已。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"그러니 비켜라!","JPN":"だからどけ！","ENG":"So move out of my way!","TWN":"你別妨礙我！"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"GOD_NPC_NANAHARA2_NULL","text":{"KOREA":"……그렇게 두지는 않겠네.","JPN":"……そうはさせぬ。","ENG":"...I cannot allow that.","TWN":"…我不能坐視不管。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":null,"text":{"KOREA":"허억……!","JPN":"はあっ……！","ENG":"*Gasp...!*","TWN":"呼呼……！"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L33_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"여긴……?","JPN":"ここは……？","ENG":"Where am I?","TWN":"這裡是……？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"안 좋은 꿈이라도 꾼 거니?","JPN":"悪夢でも見たの？","ENG":"Did you have a nightmare?","TWN":"你做惡夢了嗎？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"당주님……?","JPN":"当主……？","ENG":"Lady Nanahara...?","TWN":"堂主……？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"안심해. 집으로 데려왔어.","JPN":"安心しなさい。ここは家よ。","ENG":"Rest assured. We're home.","TWN":"沒事了，是我們把你帶回來的。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"남동방 중대의 사람들은…… 어떻게 됐습니까?","JPN":"南東軍中隊の方たちは……どうなったのですか？","ENG":"The troops in Southeast Division... What happened to them?","TWN":"東南方中隊……他們人呢？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"우리가 도착했을 땐 이미 늦었더구나.","JPN":"私たちが着いた頃にはもう遅かった。","ENG":"We were too late.","TWN":"我們到的時候已經為時已晚。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L41_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"……죄송합니다.","JPN":"……申し訳ございません。","ENG":"...My apologies.","TWN":"……抱歉。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L42_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"제가 가문연합의 사람들을 지키지 못해서……","JPN":"連合の方たちを守れず……","ENG":"I failed to protect the people in our Alliance...","TWN":"我沒能保護家族聯盟的人……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L43_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그런 자책은 아직 해선 안 돼.","JPN":"まだ自分を責めるには早いわ。","ENG":"You shouldn't wallow in self-pity just yet.","TWN":"你先別自責，"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그들이 무엇 때문에 그런 화를 당했는지 알아내고, 그 원흉을 해결하기 전까지는 감정에 휩쓸리지 말아야 한다.","JPN":"彼らが何のためにそのようになったのかを明かし、その元凶を解決する前までは感情に流されてはいけない。","ENG":"You must keep composed to find out and resolve what caused this tragedy.","TWN":"在我們釐清他們遇害的原因，並且解決掉兇手之前，不能陷入情緒當中。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"……알겠습니다.","JPN":"……承知しました。","ENG":"...Understood.","TWN":"……是的。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그리고 다행이야.","JPN":"それによかった。","ENG":"Also, I am relieved.","TWN":"而且太好了，"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L47_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"무사히 깨어나줘서.","JPN":"無事目を覚ましてくれて。","ENG":"That you woke up safe.","TWN":"你醒過來就好。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"쉬고 있으렴. 이제부터는 우리가 해결할 테니까.","JPN":"休んでなさい。これからは私たちが解決するから。","ENG":"Rest. We will take it from here.","TWN":"你先休息，接下來就交給我們處理。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"저도 돕겠습니다.","JPN":"私もお手伝いいたします。","ENG":"I will help as well.","TWN":"我也要幫忙。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"네 몸상태는 지금 그리 좋지 않아. 내 말을 듣도록 하렴.","JPN":"あなたの体の具合はそこまで良くないの。私の言うことを聞きなさい。","ENG":"You are not well right now. Please do as I say.","TWN":"你現在的身體狀況不太好，聽我的話。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"저는 당주님의 호위입니다. 고작 이런 상처 때문에 당주님을 혼자 둘 수는……!","JPN":"私は当主の護衛です。この程度の怪我で当主をお一人にするわけには……！","ENG":"But I am your bodyguard. I cannot leave you because of a minor wound...!","TWN":"我是堂主的護衛，怎麼能因為一點小傷就放堂主獨自……！"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L6_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"치후유, 이건 널 위해서 하는 말이야.","JPN":"千冬、これはあなたのために言ってることなの。","ENG":"Chifuyu, this is for your own good.","TWN":"千冬，我是為你好。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"제가 당주님보다 약한 호위이기 때문인가요?","JPN":"私が当主より弱い護衛だからですか？","ENG":"Is it because I am weaker than you?","TWN":"是因為我這個護衛比堂主還弱嗎？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그런 이유가 아니야.","JPN":"そんな理由ではないわ。","ENG":"No. That is not the reason why.","TWN":"不是的。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"그렇다면 왜…… 연합원들이 모두 움직일 때 저만 데려가지 않으신 겁니까?","JPN":"それならなぜ……連合員全員が動く時に私だけ置いて行かれたのですか？","ENG":"Then why... Why won't you take me with you when the other members are?","TWN":"那為什麼……聯盟全員出動時，卻只扔下我一個人？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"휴가를 명목으로 저를 혼자 떨어트린 이유가 무엇인가요?","JPN":"休みの名目で私を一人だけ引き離した理由は何ですか？","ENG":"What is your reason for using my resting as an excuse for leaving me behind?","TWN":"用休假的名義甩開我的理由是什麼？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"치후유, 난 네가 단지 무리하지 않았으면 해서……","JPN":"千冬、私はただあなたに無理をしてほしくなくて……","ENG":"Chifuyu, I just wish you wouldn't push yourself too hard...","TWN":"千冬，我只是不希望你太勉強自己……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"저는 당주님의 호위입니다! 제가 바라는 건……!","JPN":"私は当主の護衛です！　私が望んでいることは……！","ENG":"I am your bodyguard, Lady Nanahara! All I want is–!","TWN":"我是堂主的護衛！我在意的……！"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"큭……!","JPN":"くっ……！","ENG":"Khhk...!","TWN":"呃……！"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L16_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"치후유!","JPN":"千冬！","ENG":"Chifuyu!","TWN":"千冬！"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"오른팔의 상태가…… 좀전보다 나빠졌어.","JPN":"右腕の状態は……さっきより悪くなっているわ。","ENG":"Your right arm... It is worse than before.","TWN":"右手臂的情況……好像比剛剛還嚴重。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"의사에게 맡기라고 하셨지만, 역시 내가 치료하는 편이……","JPN":"医者に任せるようにと言われたけど、やはり私が治療した方が……","ENG":"I know I told you to see a doctor, but perhaps it will be better for me to treat it myself...","TWN":"雖然說要交給醫生處理，但還是我來……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"……읏?!","JPN":"……うっ！？","ENG":"Ngh...?!","TWN":"……唔？！"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"당주님? 괜찮으십니까?","JPN":"当主？　大丈夫ですか？","ENG":"Lady Nanahara! Are you okay?","TWN":"堂主？您沒事吧？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L26_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"하아, 너희 자매는 어지간히 좋게 얘기해선 말을 안 듣는구만.","JPN":"はあ、お主たち姉妹は優しく言っても耳に入らんようじゃのう。","ENG":"*Sigh* You two never listen, do you?","TWN":"哀，你們姊妹還真像，都是講不聽的人。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"나오님! 당주님께서 쓰러지셨습니다! 어서 의사를……!","JPN":"ナオ様！　当主が倒れました！　すぐに医者を……！","ENG":"Miss Nao! Lady Nanahara has fainted! We need a doctor...!","TWN":"奈緒大人！堂主昏倒了！快找醫生……！"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"시끄럽다, 꼬맹이!","JPN":"うるさい、小童！","ENG":"Silence, Girl!","TWN":"吵死了，小鬼！"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L31_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"작은 당주, 능력으로 치유하지 말라고 일러뒀거늘. 왜 주의를 듣지 않은 게냐?","JPN":"チビ当主、能力で治癒するなと言ったはずじゃ。どうしてわしの言うことを聞かんのじゃ？","ENG":"I told you to not use your powers to treat others, Ladychild. Why do you defy me?","TWN":"小堂主，我早就吩咐過你不要使用能力來治療，為什麼把我的話當耳邊風？！"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"죄송…… 합니다.","JPN":"申し訳……ございません。","ENG":"My... apologies.","TWN":"對不……起。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"치후유의 상처가 너무 심해서 그냥 둘 수가 없었어요.","JPN":"千冬の傷がひどすぎて放っておくわけにはいきませんでした。","ENG":"Chifiyu's wounds were too grave to ignore.","TWN":"千冬的傷勢太嚴重，我沒辦法袖手旁觀。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"하지만 전혀 치료가 되지 않는 것 같네요.","JPN":"ですがまったく治療できてないみたいです。","ENG":"Nevertheless, it appears that my efforts were in vain.","TWN":"只是好像完全沒辦法進行治療？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"신의 피를 억지로 정화하려 들면 반발이 생기는 것이 당연하지.","JPN":"神の血を無理やり浄化しようとすれば当然反動が来よう。","ENG":"Of course you'll suffer the consequences for trying to purify divine blood.","TWN":"硬要淨化神的血液當然會產生反彈。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"신의 피……? 그게 무슨 말씀이신가요?","JPN":"神の血……？　それはどういうことですか？","ENG":"Divine blood...? I don't understand.","TWN":"神的血液……？什麼意思？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"하야미의 제자. 하바키 일당들이 널 붙잡았을 때 무슨 짓을 했는지 기억하느냐?","JPN":"速水の弟子よ、覇吐の連中がお主を捕まえた時何をしたか覚えているか？","ENG":"Apprentice of Hayami, do you remember what Habaki's men did to you the day you were caught?","TWN":"速水的徒弟，你還記得幅木他們抓到你時，對你做了什麼嗎？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L41_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"주삿바늘과…… 피가 끓는 듯한 통증 이후로는…… 잘 기억이 나지 않습니다.","JPN":"注射の針と……血が沸くような苦しみの後は……よく覚えておりません。","ENG":"I remember needles... and a burning sensation in my veins... The rest is all hazy.","TWN":"他們對我進行注射……接著我感受到一股彷彿血液沸騰般的痛楚……之後的事就完全不記得。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L43_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그자들이 치후유에게 무슨 짓을 했는지 아시나요?","JPN":"あの者たちが千冬に何をしたのかご存じなのですか？","ENG":"Do you know what they did to Chifuyu?","TWN":"您知道他們對千冬做了什麼嗎？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"안 그래도 녀석의 혈액을 분석하고 오는 길이다.","JPN":"ちょうどそいつの血液を分析してきたところじゃ。","ENG":"I am on my way back from analyzing her blood.","TWN":"我來就是要分析這傢伙的血液的。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"그 무쇠머리 놈이 내 피를 빼돌려 녀석의 몸에 넣은 모양이더구나.","JPN":"あの機械頭がわしの血を抜いてそいつの体に入れたようじゃ。","ENG":"It appears that ironhead stole my blood and injected it into her.","TWN":"那個鐵面男可能把我的血液注射到這傢伙的體內了。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"나오님의 피……?","JPN":"ナオ様の血……？","ENG":"Y-your blood, Miss Nao...?","TWN":"奈緒大人的血……？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"실험 관찰 결과…… 고통을 호소하는 것 외에 긍정적인 변화는 보이지 않는군.","JPN":"実験観察の結果……苦痛を訴える以外にポジティブな変化は見られないな。","ENG":"Test result... No signs of positive effects apart from showing pain.","TWN":"實驗觀察結果……除了哀號之外，沒有看到預期的變化。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"그러고보니……","JPN":"そういえば……","ENG":"Now that I think of it...","TWN":"這麼說來……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"의식을 잃기 전, 그자가 이걸 실험이라고 부르는 것을 들었습니다.","JPN":"意識を失う前に、あの者がこれを実験と呼んでいるのを聞きました。","ENG":"Before I lost consciousness, I heard him calling this \\"an experiment\\".","TWN":"我失去意識之前，聽到他說這是個實驗。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"실험이라고?","JPN":"実験ですって？","ENG":"An experiment?","TWN":"實驗？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"그게 사실이라면 놈은 제 정신이 아닌게로군.","JPN":"それが本当だとするとやつは狂っておるな。","ENG":"If what you say is true, then he is truly out of his mind.","TWN":"若她所言屬實，我看鐵面男的腦子應該不太正常。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"그 많은 자기 병사들을 고작 실험 하나를 위해 바친 셈이니 말이야.","JPN":"あの数の兵士をたかが実験のために捧げたわけだからのう。","ENG":"Sacrificing all those men just for an experiment...","TWN":"犧牲這麼多兵力，只為了一個區區的實驗。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"바치다니…… 그게 무슨 뜻입니까?","JPN":"捧げる……それはどういう意味ですか？","ENG":"Sacrifice? What do you mean by that?","TWN":"犧牲……這是什麼意思？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"네 녀석이 의식을 잃고, 명부검을 휘둘러 그것들을 죄다 베어버렸거든.","JPN":"お主が意識を失い、冥府剣を振り回してあやつらを全部斬ってしまったのじゃ。","ENG":"When you lost consciousness, you swung your Nether God’s Sword and slashed through everyone there.","TWN":"你失去意識後，拿著冥府劍把人家都給斬了。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L10_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"제가…… 말입니까? 하지만 어떻게?","JPN":"私が……ですか？　しかし、どうやって？","ENG":"I... did what? But how?","TWN":"你說……我？怎麼可能？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"내가 가진 명부신의 피가 네놈의 영혼을 파고들어 검을 움직일 힘을 준 것이지.","JPN":"わしの持つ冥府の神の血がお主の魂に入り込み、刀を振るう力を与えたのじゃ。","ENG":"The Nether God's blood has permeated your soul, endowing you with the capacity to wield that sword.","TWN":"我身上的冥府神血液滲入你的靈魂，使你有力量可以揮動冥府劍。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"그렇다면…… 나오님의 피가 명부신과 같은 힘을 얻게 한다는 말씀입니까?","JPN":"ならば……ナオ様の血が冥府の神のような力を与えてくれるということですか？","ENG":"Then... are you saying that your blood has the same properties as those of the Nether God?","TWN":"意思是……奈緒大人的血讓我獲得與冥府神一樣的力量嗎？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"이번엔 운이 좋았을 뿐이야. 인간의 신체와 영혼은 보통 환상종의 피를 감당하지 못해.","JPN":"今回は運が良かっただけじゃ。人間の体と魂は普通、幻想種の血に耐えられん。","ENG":"You were lucky this time. A human's body and soul normally cannot withstand the blood of Bygones.","TWN":"這次只能算你運氣好，人類的身體和靈魂是無法負荷夢幻類的血的。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L14_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"제아무리 나나하라의 혈통이라 해도, 신의 피에 취하면 영혼이 잡아 먹히고 만다.","JPN":"いくら七原の血統とは言え、神の血に酔えば魂が喰われてしまう。","ENG":"Even if you are of Nanahara blood, divine blood tends to eat away at your soul.","TWN":"即使是七原的血統，在神的血液裡靈魂也會被吞噬掉。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"하지만…… 그 피의 힘을 잠시나마 빌릴 수 있다면, 예견에 어울리는 무사가 될 수 있겠지요.","JPN":"ですが……その血の力をしばし借りることができれば、予言に相応しい武士になれます。","ENG":"But then... If I can borrow that power for a while, I could become the warrior that the foresight says.","TWN":"但……若是能暫時借用血的力量，那我就可以成為預言中的武士吧？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"그렇게 해서라도 제가 역신베기를 완성할 수 있다면……!","JPN":"そうしてでも私が大蛇薙剣を完成できるとしたら……！","ENG":"If that is what it takes for me to complete Orochinagi...!","TWN":"那我或許就可以完成瘟神斬……！"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"어리석은 놈!","JPN":"愚か者！","ENG":"Fool!","TWN":"愚蠢的東西！"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_HIT_SMASH_SMALL_06"},{"id":"L19_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"영생을 탐하여 신의 피를 노린 인간들의 말로를 배우지 못했느냐!","JPN":"永生を貪り神の血を狙った人間の末路を学ばなかったのか！","ENG":"Have you not learned from those fools who tried to become immortal with divine blood?!","TWN":"那些貪圖永生覬覦神血液的人下場，沒能讓你學到教訓嗎！"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"다시 한번 이런 힘을 받아들였다간, 네놈은 피에 영혼이 삼켜진 빈 껍데기가 될 게다.","JPN":"再びこのような力を受け入れようものなら、血に魂を喰いつくされ抜け殻しか残らなくなる。","ENG":"If you inject yourself with this blood again, you will become a soulless, empty shell.","TWN":"要是再次接受這股力量，你就會成為靈魂遭血液吞噬的空殼子。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"죄송합니다.","JPN":"申し訳ございません。","ENG":"My apologies.","TWN":"對不起。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"하바키 놈을 잡아들일 때까지 신기를 완성하는 일은 잠시 보류다.","JPN":"覇吐を捕まえるまで神器を完成させる仕事はしばし保留とする。","ENG":"Until Habaki is captured, completing the Sacred Treasure is on hold.","TWN":"在抓到幅木前，完成神器的計畫先暫停。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L25_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"그러니 네놈도 그전까진 독단으로 행동하지 마라, 하야미의 제자.","JPN":"だから、お主もそれまでは独断で行動するでない、速水の弟子。","ENG":"So, until then, apprentice of Hayami, no acting on your own will.","TWN":"在那之前你也不准擅自行動，知道嗎，速水的徒弟？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"……예.","JPN":"……はい。","ENG":"...Understood.","TWN":"……是。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"나 참. 가문연합에 어쩌다 저런 철부지 꼬맹이들만 남게 된 건지.","JPN":"まったく。なぜ連合に残っている者はあんな世間知らずの小童ばかりなのじゃ。","ENG":"Ugh. How did the Family Alliance end up with all these kids?","TWN":"傷腦筋，家族聯盟裡怎麼全都只剩下這些搞不清楚狀況的小鬼！"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"지난 세월 동안 많은 일들이 있었지요.","JPN":"これまで色々なことがありました。","ENG":"A lot has happened in the past years.","TWN":"以前曾經發生過很多事，"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"신들에겐 찰나의 시간일지 모르나, 저희 같은 사람들에겐 모든 게 변하는 시간입니다.","JPN":"神々には刹那に過ぎないかもしれませんが、私たちのような人間にはすべてが変わりうるほどの時間です。","ENG":"It may be a brief moment to gods, but it is enough time for everything to change for humans.","TWN":"對神而言或許是剎那間的時間，但我們人類而言卻是巨變。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"녀석들의 경솔함을 감싸는 거냐? 냉철하게 판단하는 하야미 가문답지 못하구나.","JPN":"やつらの愚かな行動を庇っているのか？　冷徹に判断する速水家らしくないのう。","ENG":"Are you covering for their carelessness? You are nothing like the Hayamis that I once knew.","TWN":"你現在是在替他們的草率開脫嗎？一點也不像速水家族總是冷靜判斷的作風。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"얼마 전, 역신이 봉인에서 풀려나는 일이 있었습니다.","JPN":"少し前に、疫病神の封印が解かれる事件がございました。","ENG":"Recently, the Plague God was released from her seal.","TWN":"瘟神不久前從封印中被釋放出來，"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"당주님은 천총운검으로 목숨을 바쳐 이를 막고자 했으나, 치후유님과 연합원들의 도움으로 그 운명이 바뀌었지요.","JPN":"ご当主様は天叢雲剣で自らの命を捧げ、それを止めようとされました。しかし、千冬様と連合員の協力でその運命が変わったのです。","ENG":"Lady Nanahara attempted to sacrifice her life to stop it with her Sword of Kusanagi. However, fate had changed thanks to the efforts of Chifuyu and the other members.","TWN":"堂主本想拿天叢雲劍獻上自己的性命來阻止這件事，多虧千冬和聯盟成員的幫助才改變命運。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"……뭐?","JPN":"……何じゃと？","ENG":"...What?","TWN":"……什麼？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"그렇다면 저 작은 당주가 멀쩡히 살아서 오로치의 재림을 막았다는 거냐?","JPN":"ならば、あのチビ当主は無傷でオロチの復活を止めたということか？","ENG":"Then are you telling me that Ladychild stopped Orochi's resurgence and survived?","TWN":"你的意思是，那個小堂主是活生生地阻止大蛇再次來到？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"오로치의 재림을 막으려면 무녀의 희생은 반드시 필요했을 텐데?","JPN":"オロチの復活を止めるためには必ず巫女の犠牲が必要なはずじゃ。","ENG":"Was not a sacrifice of a priestess needed in order to stop Orochi's resurgence?","TWN":"但要阻止大蛇再次來到，巫女的犧牲是不可或缺的。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"아무런 희생이 없었던 것은 아닙니다.","JPN":"何の犠牲もなかったわけではございません。","ENG":"I did not say there was not any sacrifice.","TWN":"不能說是毫無犧牲。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"당주님께선 천총운검의 힘을 빌어 당신의 신력을 사용하셨고, 그 대가로 바람의 목소리를 잃었습니다.","JPN":"ご当主様は天叢雲剣の力を借りてご自分の神力をお使いになり、その代償として風の声を失われました。","ENG":"Lady Nanahara borrowed the powers of the Sword of Kusanagi to use her divine powers. As a result, she has lost the voice of wind.","TWN":"堂主借助天叢雲劍的力量使用自己的神力，然而代價就是失去風聲。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"……사람을 상대로 신력을 쓴 게로군.","JPN":"……人間を相手に神力を使ったのだな。","ENG":"...So she used her divine powers on another person...","TWN":"……因為把神力拿來救人吧。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"당주님의 선택이 아니었다면 저와 치후유님은 살아남지 못했을 겁니다.","JPN":"当主様のご決断がなかったら私と千冬様は今ここにおりません。","ENG":"If it were not for Lady Nanahara's call, Miss Chifuyu and I wouldn't have survived.","TWN":"若非堂主的選擇，我和千冬可能早已不在人世。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"그랬다면…… 나오님께서 찾으시는 나나하라에 무사는 한 사람도 남지 않았겠지요.","JPN":"そうなれば……ナオ様がお探しの七原に武士は一人も残っていなかったでしょう。","ENG":"If that had happened... there will be no warrior in the Nanahara family whom you are looking for.","TWN":"那麼……您找上的七原中也就不再有任何武士存在。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"그래서……?","JPN":"で……？","ENG":"So...?","TWN":"所以呢……？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"나더러 당주 녀석을 칭찬이라도 해달라는 거냐?","JPN":"わしに当主を褒めろとでもいうのか？","ENG":"Are you implying that I should praise her?","TWN":"你現在是要我誇獎那個小堂主好棒嗎？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"작은 당주가 생명의 기적을 대가로 바람의 목소리를 잃었다는 건, 가문연합이 다음 운명을 미리 알고 대비할 수 없다는 뜻이다.","JPN":"チビ当主が命の奇跡の代償として風の声を失ったということは、連合が次の運命をあらかじめ知り、備えることができないということじゃ。","ENG":"The fact that this Ladychild performed a miracle at the cost of losing the voice of wind means that the Family Alliance has no way of foreseeing fate and preparing for it.","TWN":"小堂主失去風聲，也就表示家族聯盟將無法再防患未然。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"바로 지금, 배반자 놈 하나 때문에 우리가 궁지에 몰린 것처럼 말이지.","JPN":"ちょうど今も、裏切り者一人のせいでわしらが窮地に追い込まれているではないか。","ENG":"Just like how we are cornered because of one traitor.","TWN":"我們現在才會因為一個叛徒就被逼到絕境。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"알고 있습니다.","JPN":"わかっております。","ENG":"Of course.","TWN":"我知道。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L1_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"하지만 소인은 주어진 운명보다……","JPN":"ですが、私は与えられた運命より……","ENG":"However, I want to put my trust in the heart of people...","TWN":"但我不想相信既定的命運……"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"서로를 지키고자 하는 사람의 마음을 믿고 싶습니다.","JPN":"お互いを守ろうとする人の心を信じたいのです。","ENG":"Rather than in a predetermined fate.","TWN":"我想相信人們彼此守護的心。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"여기에 계십시오, 전대장님. 놈들을 막는 건 저희에게 맡겨 주시면 됩니다.","JPN":"ここにいてください、戦隊長。やつらを止めるのは私たちにお任せください。","ENG":"Please stay here, Commander. Leave it to us to block them.","TWN":"請戰隊長待在這裡，其他人就交給我們處理。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"무슨 일이 있어도, 절대로 밖으로 나오지 마세요.","JPN":"何があっても、絶対に外に出ないでください。","ENG":"Whatever happens, never step outside.","TWN":"無論發生什麼事都絕對不要出來。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"이번엔 저희가 대장님을 구해드릴 테니까요.","JPN":"今度は私たちが隊長を助けますから。","ENG":"It's our turn to save you.","TWN":"這次換我們救戰隊長。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"하아…… 가문연합도 예전 같질 않구만.","JPN":"はあ……連合も変わったのう。","ENG":"*Sigh...* The Family Alliance is not what it was before.","TWN":"哀……家族聯盟也早就人事已非，"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"이놈이나 저놈이나 꿈같은 소릴 지껄이고 말이야.","JPN":"どいつもこいつも夢のような話ばかり言う。","ENG":"Everyone here seems to be daydreaming.","TWN":"每一個人都在痴人說夢話。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"넌…… 내가 원망스럽지 않으냐?","JPN":"お主は……わしを恨んではおらんのか？","ENG":"You... Do you resent me?","TWN":"你……不恨我嗎？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"살아있으면서 여태 낯짝 한 번 안 비추던 자가 이제서야 나타났는데 말이지.","JPN":"生きているにもかかわらず、今まで顔を出したこともない者が今更のこのこやって来たんだぞ。","ENG":"I have been alive for all these years, and yet, I decided to show up now.","TWN":"明明還活著，卻從未露過面，一直到現在才出現。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"모든 일이 뜻대로 순탄하게 흘러가지만은 않는 법이지요.","JPN":"すべてが思いどおり順調にいくことなどありえません。","ENG":"Not everything can be as we plan them to be.","TWN":"並非所有事情都能如我們所願，"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"나오님께서도 그럴 수밖에 없는 사정이 있었을 거라 생각합니다.","JPN":"ナオ様にもそうするしかない事情がおありだったのでしょう。","ENG":"I'm sure you had your reasons to do so, Miss Nao.","TWN":"我相信您也是逼不得已的。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"……흥.","JPN":"……ふん。","ENG":"...Hmpf.","TWN":"……哼。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"그렇게 말해도, 지금의 당주가 불안한 건 변함없는 사실이다.","JPN":"そうは言っても、今の当主が不安であることには変わりない。","ENG":"Even if you say that, it does not change the fact that the current leader of Nanahara is unstable.","TWN":"就算你這麼說，現在的堂主令人擔憂還是事實。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"지금의 선택을 후회하지나 말거라. 날개 부러진 새에게 다음 기적은 없을 테니.","JPN":"今の選択を後悔するでないぞ。翼が折れた鳥にもう奇跡は起こらん。","ENG":"Do not regret the choices you made. A wingless bird will never get another chance to fly.","TWN":"不要對現在的選擇後悔，折翼的鳥是不會再有下一個奇蹟的。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"……낭떠러지인 줄 알면서도 기적을 바라고 뛰어들진 않습니다.","JPN":"……崖であることを知りながら、奇跡を願って飛び込んだりはしません。","ENG":"I do not pray for a miracle whilst knowing that the edge of a cliff is nearing.","TWN":"……我不會對著懸崖縱身而下期待有奇蹟出現，"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"하지만 적어도 날갯짓은 해봐야겠지요.","JPN":"でも、少なくとも飛ぼうとはしてみなければ。","ENG":"However, I will at least try to flap my wings.","TWN":"但至少可以嘗試看看振翅飛翔。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L26_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"장님 동굴……","JPN":"晦冥の洞窟……","ENG":"The Cave of Blinds...","TWN":"盲穴……"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"이곳에서 하야미 공과 마지막으로 수련을 한 지도 꽤 많은 시간이 흘렀구나.","JPN":"ここで速水殿と最後に修練をしてからずいぶんと経ったものだな。","ENG":"A long time has passed since my last training with Dame Sanae here.","TWN":"上次和速水在這裡練習也已經是好久以前的事呢。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"어떤 느낌이 드시는지요?","JPN":"どんな感じがしますか？","ENG":"How do you feel?","TWN":"您有什麼感覺？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_YOUNG","text":{"KOREA":"이 동굴은 서늘하고…… 어두워서 아무것도 보이지 않습니다.","JPN":"この洞窟は涼しく……暗くて何も見えません。","ENG":"The cave is too cold... and too dark to see anything.","TWN":"這個洞穴又冷……又黑，我什麼都看不到。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"그렇다면 벽을 한 번 손으로 짚어 보시지요.","JPN":"でしたら、一度壁を触ってみてください。","ENG":"Then try placing your hand on the wall.","TWN":"您用手摸摸看牆壁。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_YOUNG","text":{"KOREA":"이건……? 마치 짐승의 발톱이 무수히 할퀴고 지나간 듯한……","JPN":"これは……？　まるで獣が爪で何度もひっかいたような……","ENG":"Hmm...? It's as if a beast ran its claws through it...","TWN":"這是……？好像被野獸抓過的痕跡……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_YOUNG","text":{"KOREA":"……아니, 아주 예리한 검의 날끝이 베고 지나간 흔적이군요.","JPN":"……いや、とても鋭い刃先でつけられた跡ですね。","ENG":"...No. These are markings of a sharp blade.","TWN":"……不對，應該非常銳利的刀鋒劃過的痕跡。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"이곳은 오래 전, 명부신께서 검술을 연마하셨던 장소입니다.","JPN":"ここは昔、冥府の神が剣術を鍛錬なさった場所です。","ENG":"This is where the Nether God used to practice his swordsmanship a long time ago.","TWN":"這裡很久以前是冥府神練劍的地方。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"처음에는 작은 바위산이었으나, 수천년에 걸쳐 검술을 연마한 끝에 이런 깊은 동굴이 만들어졌다고 하지요.","JPN":"最初は小さな岩山でしたが、数千年にわたる剣術の鍛錬により、ついにはこのような深い洞窟になったと伝えられています。","ENG":"It used to be a small mountain. But after thousands of years of slashing, a deep cave was formed.","TWN":"原本是個小小的石頭山，經過數千年在此練劍後，最後變成一個很深的洞穴。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_YOUNG","text":{"KOREA":"신이 이런 곳에서 수련을 했다니…… 무척 신기합니다.","JPN":"神がこんなところで修練を……とても不思議です。","ENG":"It's astonishing to learn that a god once trained in a place like this...","TWN":"神竟然曾經在這種地方練劍……好神奇喔。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_YOUNG","text":{"KOREA":"그럼 이 벽에 새겨진 검자국들이 명부신의 검술인 건가요?","JPN":"それでは、この壁に残された刀傷が冥府の神の剣術なのですか？","ENG":"So all these markings on the wall are traces of the Nether God's sword skills?","TWN":"那刻在牆壁上的劍痕就是冥府神的劍法嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"그렇습니다. 이 동굴에 새겨진 명부신의 검술을 해석하여 풀이한 것이 나나하라류의 원류.","JPN":"そのとおりです。この洞窟に刻まれた冥府の神の剣術を解釈して説いたのが七原流の源流。","ENG":"Correct. The origin of the Nanahara style was made by interpreting the engraved markings of this cave made by the Nether God.","TWN":"沒錯，將刻在洞穴中的冥府神劍法分析解釋後，於是形成最初的七原流。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"저희 가문에서 명검이라 불리는 이들은 모두 이 동굴에서 수행했지요.","JPN":"速水家で名を馳せた者たちはみなこの洞窟で修行いたしました。","ENG":"Even the greatest sword masters in my family have all trained inside this cave.","TWN":"我們家族中稱為名劍的人，都曾在這個洞穴裡修行過。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"그러나 수많은 인재들이 거쳐갔음에도, 그것을 완벽히 이해한 자는 한 명도 없었습니다.","JPN":"ですが、数多くの才能ある者たちがここで修練しましたが、冥府の神の剣術を完璧に理解できた者はおりませんでした。","ENG":"But even though many talented individuals have come and gone, no one has been able to fully understand it.","TWN":"然而即使有那麼多的人才曾來這裡取經，卻沒有一個人能夠完全理解冥府神的劍法。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_YOUNG","text":{"KOREA":"제가 이런 곳에 들어올 자격이 되는 걸까요?","JPN":"私などがここに入る資格があるのでしょうか？","ENG":"Do you think I am qualified to even be here?","TWN":"我有資格進來這裡嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"치후유님께선 이미 제가 가르칠 수 있는 나나하라류의 모든 것을 받아들이셨습니다.","JPN":"千冬様にはすでに私に教えられる七原流のすべてをお教えしました。","ENG":"You have already surpassed all that I can teach you about the Nanahara style, Miss Chifuyu.","TWN":"我已經將我畢生所學的七原流都傳授給您，而您也已經學會。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"더 나아가 극의를 깨우치고 싶으시다면, 이 방법이 유일한 길이겠지요.","JPN":"さらに極意を悟りたければ、これが唯一の方法となるでしょう。","ENG":"If you want ultimate realization, this is the only way.","TWN":"若想再邁向更高境界，這是唯一的辦法。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"narration","speaker":null,"text":{"KOREA":"그 뒤로 한동안 동굴에 새겨진 칼날의 길을 암기하며 수련을 거듭했다.","JPN":"それ以来、しばらく洞窟に刻まれた刃先の流れを暗記しながら修練を重ねた。","ENG":"After that day, I trained inside that cave, memorizing the blade's path engraved on the wall.","TWN":"在那之後，我記下刻在洞穴裡的每一條劍痕，不斷反覆練習。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L2_1","type":"narration","speaker":null,"text":{"KOREA":"하지만 결국 성공하지 못했다.","JPN":"だが、結局成功しなかった。","ENG":"But in the end, I was not able to succeed.","TWN":"結果還是失敗收場。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"narration","speaker":null,"text":{"KOREA":"흠집을 따라 검을 휘두르는 것은 가능했으나, 그 동세는 무척이나 부자연스러웠다.","JPN":"傷跡をなぞって刀を振るうことは可能だったが、その動きはとても不自然だった。","ENG":"I was able to replicate the swing along the path, but the momentum was unnatural.","TWN":"雖然可以模仿痕跡揮劍，姿勢卻非常不自然。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"narration","speaker":null,"text":{"KOREA":"어쩌면 이것이 타고나지 못한 자의 한계일지도 모른다.","JPN":"もしかするとこれが生まれつき才能のない者の限界なのかもしれない。","ENG":"Perhaps this was the limit for the untalented.","TWN":"或許一個沒有天賦的人天生就是做不來。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"narration","speaker":null,"text":{"KOREA":"하지만 당주님을 또다시 지키지 못할 상황이 오게 된다면 나는……","JPN":"でも、また当主を守れなくなる状況が来れば私は……","ENG":"But if there ever is another time when I am not able to protect Lady Nanahara, I...","TWN":"不過要是又發生無法保護堂主的情況，那我……"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"하아……","JPN":"はあ……","ENG":"*Sigh*","TWN":"哀……"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"근심이 있어 보이는 한숨소리로군요.","JPN":"悩みがありそうな溜息ですね。","ENG":"That is one worrisome sigh.","TWN":"您看起來好像有心事。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"하야미 공? 여긴 어쩐 일로 오셨습니까?","JPN":"速水殿？　ここにはどうして？","ENG":"Dame Sanae? What brings you here?","TWN":"速水？你來這裡做什麼？"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"당주님의 분부로 명을 수행하고 돌아오는 길입니다.","JPN":"当主様に命ぜられた仕事を片付けて帰ってきたところです。","ENG":"I am on my way back from carrying out an order from Lady Nanahara.","TWN":"我剛完成堂主的吩咐回來。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L13_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"그리고, 나오님께서 이 검을 돌려주라고 하시더군요.","JPN":"それに、ナオ様がこの刀を返すようにと。","ENG":"Also, Miss Nao told me to give this blade back to you.","TWN":"另外，奈緒大人請我把這把劍還給您。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"감사합니다.","JPN":"ありがとうございます。","ENG":"Thank you.","TWN":"謝謝你。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"날이 전보다 예리해졌음에도 무게는 여전히 같군요. 신기합니다.","JPN":"刃が前より鋭くなっているのに重さは変わらない。不思議です。","ENG":"It's strange. The edge is sharper than before, but it seems to weigh the same.","TWN":"雖然刀鋒比以前銳利，重量卻一點也沒變，真是神奇。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"나오님은 저희 하야미 집안의 도구도 여럿 만들어주신 무기의 장인이시니까요.","JPN":"ナオ様は速水家の道具も多く作ってこられた武器職人ですから。","ENG":"That is because Miss Nao is a master weaponsmith who has been forging various tools for the Hayami family.","TWN":"奈緒大人也替我們速水家族製造過一些武器，她可是武器達人呢。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L18_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"……한 사람의 도움이 더 필요한 때에 이런 꼴을 보여 면목이 없군요.","JPN":"……一人でも多くの手が必要な時にこんな姿をお見せして面目ありません。","ENG":"...I'm sorry to be like this when you need every help you can get.","TWN":"……現在正需要人手的時候，我卻是這副德性，真是沒臉見人。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L19_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"그런 말씀 마십시오. 치후유님의 노력을 이해하지 못하는 연합원은 없습니다.","JPN":"何をおっしゃいますか。千冬様の努力を理解できない連合員はいません。","ENG":"Don't be. Every member understands the effort you put into, Miss Chifuyu.","TWN":"別這麼說，大家都能理解你的努力的。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"그간의 수련이 무색하게도, 저는 오른팔을 움직이지 못하게 됐습니다.","JPN":"これまでの修練もむなしく右腕が動かなくなりました。","ENG":"But even with all the training, I cannot move my right arm now.","TWN":"這陣子的練習也派不上用場，我的右手臂完全無法動彈。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"회복할 수 있는 상처인지도 불분명하다고 합니다.","JPN":"回復できる傷なのかも定かではありません。","ENG":"They cannot tell if this wound will even ever heal.","TWN":"而且是否能夠痊癒也是個未知數，"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"이대로는 지금의 저는 당주님에게 짐이 될 뿐입니다.","JPN":"このままでは、私は当主の足手まといになるだけです。","ENG":"At this rate, all I will be is a burden to Lady Nanahara.","TWN":"這樣下去，現在的我只會成為堂主的負擔。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"치후유님은 나나하라류의 모든 것을 익히셨습니다. 더는 수련을 통해 성장할 수 없을 정도로 말이지요.","JPN":"千冬様は七原流のすべてを身につけました。もう修練を通じては成長できないほどに。","ENG":"You have learned everything there is to know about the Nanahara style, Miss Chifuyu. Enough so that more training will not improve your skills.","TWN":"您已經熟悉七原流的劍法，再練下去也無法進步的。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"알고 있습니다. 이런 상태로 수련장소를 찾는다고 해서 달리 방도가 없다는 건……","JPN":"わかっているんです。このような状態で修練場を訪れても解決の糸口は見つからないと……","ENG":"I think so too. I know that training in this state will not change anything...","TWN":"我知道，在這種狀態下來到修練的地方也無計可施……"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"그럼에도 미련이 남아, 이곳에 발길이 닿았을 뿐입니다.","JPN":"それでも未練がましくここに来てしまいました。","ENG":"But there is still this lingering feeling, which is why I came here.","TWN":"只是我還是放不下，才會來這裡。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"치후유님은 장님동굴에 새겨진 검식들을 모두 암기하고 계시는지요?","JPN":"千冬様は晦冥の洞窟に刻まれている傷をすべて暗記なさっていますか？","ENG":"I have heard you memorized every marking in the Cave of Blinds, correct?","TWN":"您有把刻在盲穴中的招式都背下來對吧？"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"기억은 하고 있으나, 그것을 검술로 구현할 역량은 되지 못합니다.","JPN":"覚えてはいますが、それを剣術として具現化する力量はありません。","ENG":"I have, but I lack the ability to incorporate it into my combat techniques.","TWN":"我是還記得，但那不足以成為一套劍法。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"더군다나 지금은 팔을 다쳤으니까요.","JPN":"それに今は腕を怪我してもいます。","ENG":"Even more so, because of the state of my arm.","TWN":"更何況我現在手臂還受傷。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"팔 하나를 쓰지 못해도 방법은 있습니다.","JPN":"腕一本使えなくとも方法はあります。","ENG":"There are still ways to use it with one arm.","TWN":"就算有一隻手臂無法使，還是有辦法的。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"가르침은 아니지만, 원하신다면 치후유님이 더 강한 적에게 맞설 수 있도록 도움을 드리지요.","JPN":"教えではありませんが、よろしければ千冬様がより強い敵に立ち向かえるようお手伝いいたしましょう。","ENG":"Miss Chifuyu, I'm not trying to teach you anything. However, I can help you so that you can take on more formidable opponents if you wish.","TWN":"不敢說是教，但您若願意，我可以幫助您能夠面對更強大的敵人。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"정말로 그런 방법이 있습니까?","JPN":"本当にそのような方法があるのですか？","ENG":"Is there really a way?","TWN":"你真的有辦法嗎？"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};